import java.util.*;

public class TaskScheduler {

    static class Task {
        String name;
        int burstTime;
        Task(String name, int burst) { this.name = name; this.burstTime = burst; }
    }

    public void schedule(List<Task> tasks, int quantum) {
        Queue<Task> queue = new LinkedList<>(tasks);
        int time = 0;
        while (!queue.isEmpty()) {
            Task task = queue.poll();
            int run = Math.min(task.burstTime, quantum);
            System.out.printf("t=%d: %s runs for %d units%n", time, task.name, run);
            time += run;
            task.burstTime -= run;
            if (task.burstTime > 0) {
                // TODO: re-enqueue because task is not finished
            } else {
                System.out.printf("t=%d: %s DONE%n", time, task.name);
            }
        }
    }

    public static void main(String[] args) {
        List<Task> tasks = Arrays.asList(
            new Task("P1", 10),
            new Task("P2", 4),
            new Task("P3", 6)
        );
        new TaskScheduler().schedule(tasks, 4);
    }
}

